python - <<'PY'
import os
from collections import Counter
root = '/Users/my/Desktop/ppphd'
count = Counter()
archives = {'.zip', '.rar', '.7z', '.tar', '.gz'}
doc_ext = {'.doc', '.docx', '.pdf', '.xlsx', '.ppt', '.pptx', '.txt'}
template_dirs = ['个人模版','简历模板','模板','Templates','templates']
for dirpath, dirnames, filenames in os.walk(root):
    for fn in filenames:
        ext=os.path.splitext(fn)[1].lower()
        path=os.path.join(dirpath, fn)
        if ext in archives:
            count['archives'] += 1
        if ext in doc_ext:
            count['documents'] += 1
        if ext == '.pdf' or ext in {'.docx','.doc'}:
            count['text_documents']+=1
        if ext == '.zip':
            size=os.path.getsize(path)
            if size>150*1024*1024:
                count['large_zip']+=1
        count['total_files']+=1
    for dn in dirnames:
        if dn in template_dirs:
            count['template_dirs']+=1

print(count)
PY

